var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……열차를 멈출 방법이 없다고?","JPN":"……列車を止める方法が、ない？","ENG":"...There's no way to stop the train?","TWN":"……沒有能讓列車停下的方法？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"객차를 넘어 오면서 알아채지 않았나요?","JPN":"客車を通りながら、気付きませんでしたか？","ENG":"Did you not notice as you moved through the passenger cars?","TWN":"你一路這樣越過車廂都沒發現嗎？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"이 열차는 <color=#ffd34c>제</color>가 원하는 한 끝없이 달리게 정해져 있답니다.","JPN":"この列車は<color=#ffd34c>私</color>が望む限り、限りなく走るようになっているのです。","ENG":"This train will run endlessly as long as <color=#ffd34c>I</color> want it to.","TWN":"只要<color=#ffd34c>我</color>想要，就可以讓這台列車一直奔馳下去。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"완벽한 합주를 추구하는 그녀에게 돌이킬 수 없는 실패는 참으로 흉측한 것일 뿐.","JPN":"完璧な合奏を追求する彼女にとって、取り返しのつかない失敗は耳障りな音そのものです。","ENG":"An irreversible failure is truly hideous for someone like her who only seeks perfect harmony.","TWN":"對於追求完美合奏的她而言，無法挽回的失敗是如此醜陋。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"열차의 운행에 간섭할 여지를 남겨 둘 리 없지요.","JPN":"列車の運行に干渉する余地を残しておくわけがありません。","ENG":"She will never allow interference of any kind.","TWN":"所以她不會留下任何會影響到列車行進的餘地。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"당신이 여기 있다는 말은……. 이 열차를 움직이는 원동력이 당신이란 뜻이지?","JPN":"君がここにいるってことは……この列車を動かす原動力が君だってことよね。","ENG":"And seeing how you are here... The driving force of this train is you, I presume?","TWN":"你之所以在這裡……是因為你就是這台列車的驅動力？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"네. 인간으로서의 마지막 경험이기 때문이지요.","JPN":"はい。人間としての最後の経験ですから。","ENG":"Correct. For I am my last experience as a human.","TWN":"沒錯，這裡是我身為人類時最後的經歷。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그게 뭔지 말해 줘. 열차를 멈출 실마리가 될지도 모르니까.","JPN":"それが何なのか話して。列車を止める手がかりになるかもしれないから。","ENG":"Tell me what that is. It might be a clue to stopping this train.","TWN":"告訴我那段經歷，那可能是能夠讓列車停下的線索。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"흥미롭군요. 그렇게나 열차에서 내리고 싶으신가요?","JPN":"興味深いですね。そんなに列車から降りたいのですか？","ENG":"Interesting. Are you that eager to get off this train?","TWN":"真有趣，你就那麼想離開這台列車嗎？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"이미 벌어졌던 참상을 엿보기나 하는 악취미는 없어서.","JPN":"すでに起きた惨状を盗み見る悪趣味は持ってないの。","ENG":"Well, I have no interest in revisiting tragedies that have already happened.","TWN":"我對窺視早已發生的慘況沒有興趣。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그렇군요.","JPN":"なるほど。","ENG":"I see.","TWN":"原來如此。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"새로운 타기리온이 강림한 그 날, 저는 인정했습니다.","JPN":"新しいタギリオンが降臨したあの日、私は認めました。","ENG":"On the day the new Thagirion descended, I admitted my defeat.","TWN":"新的塔基里翁降臨的那一天，我便清楚，"},"stage":{"bg":"HARMONY2_03","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L20_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"아니. 처음부터 알고 있었지요.","JPN":"いいえ。最初からわかっていたのです。","ENG":"No, I always knew from the beginning.","TWN":"不，其實我早就知道。"},"stage":{"bg":"HARMONY2_03","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"우리 세계의 문명 수준으로는 멘탈 프린팅은 실현 불가능한 기술이란 것을.","JPN":"私たちの世界の文明レベルでは、メンタル・プリンティングなど実用不可能な技術であるということは。","ENG":"That Mental Printing technology would be impossible to accomplish in our world's current state of civilization.","TWN":"以我們的文明水準，是不可能實現智力複印的。"},"stage":{"bg":"HARMONY2_03","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"혹은, 애초에 구현할 수 없는 기술이란 것을.","JPN":"いいえ、具現化すらできない技術であるということは。","ENG":"That, or this technology could not be implemented in the first place.","TWN":"或者說，那項技術根本就無法實現。"},"stage":{"bg":"HARMONY2_03","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……뭐?","JPN":"……は？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L25_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"예하와 동일한 심상을 지닌 복제체들을 만들어낸다고 한들, 타인의 믿음으로 힘을 얻는 권능은 발현되지 않았습니다.","JPN":"猊下と同じ心像を持つ複製体を作り出しても、他人の信仰から力を得る権能は発現しませんでした。","ENG":"Even though we have created clones out of Her Eminence's image, the power of gaining fortitude from the faith of her followers was not manifested.","TWN":"雖然製造出和主教有相同心志的複製品，但靠他人的信念獲得力量的能力並沒有顯現出來。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"연구 끝에 그들이 지닌 힘의 성질이 제각각 다른 성질을 띈다는 사실을 알아냈지만….","JPN":"研究の末、彼らの持つ力の性質がそれぞれ違うという事実を突き止めはしましたが……","ENG":"Through my research, I found that the power they had exhibited different attributes, but...","TWN":"經過研究才發現，他們的力量都擁有各不相同的性質……"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그 세계에서는 CRF라고 부르던가요.","JPN":"確かそちらの世界ではCRFと呼んでいましたね。","ENG":"I presume it is called CRF in your world.","TWN":"這在那個世似乎稱為CRF。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"심상의 형태만 모방할 수 있는 멘탈 프린팅으로는, CRF의 성질까지 일치시킬 수 없었습니다.","JPN":"心像の形だけを疑似的に作り出せるメンタル・プリンティングでは、CRFの性質まで一致させることはできなかったのです。","ENG":"Mental Printing could only create a mere imitation of an image, and could not match the CRF attributes.","TWN":"智力複印只能做到模仿心志，但無法模仿CRF的性質。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그럼…. 처음부터 안 될 걸 알면서도 그런 끔찍한 실험을 벌였다고?","JPN":"じゃあ……最初から全部わかってたのに、あんなひどい実験をしたってこと？","ENG":"Then... you conducted that horrible experiment knowing that it wouldn't work from the start?","TWN":"意思是……你明知道無法實現，卻還是展開如此殘忍的實驗？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"불가능한지 알고 있었으면서…. 학살이 일어나는 걸 내버려 뒀다고?","JPN":"不可能だってわかってて……虐殺が起きることを放置したの？","ENG":"You knew it was impossible... but you let that massacre happen?","TWN":"你明明知道不可能……卻縱容殘忍的大屠殺？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그 세계에는 신이 실존합니까?","JPN":"そちらの世界には神が実存していますか？","ENG":"Does god exist in that world?","TWN":"那個世界真的有神嗎？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……닥쳐.","JPN":"……黙って。","ENG":"...Shut up.","TWN":"……住口。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"추대된 신인 예하께서 뭇 신도들의 신앙을 짊어지셨듯이….","JPN":"選ばれた神である猊下が多くの信徒の信仰をその身に受けたように……","ENG":"Just as Her Eminence carried the faith of all the believers...","TWN":"如同受人愛戴的新主教，肩負眾多信徒的信念…"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L40_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"신의 실존 여부와 관계없이, 인간은 신을 신앙합니다.","JPN":"神の実存の有無に関係なく、人間は神を信仰します。","ENG":"Humans believe in the existence of god, whether it exists or not.","TWN":"不管神是否真的存在，人類依舊信神。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"저희에게는 멘탈 프린팅 기술이 곧 그러한 믿음의 대상이었지요.","JPN":"私たちにはメンタル・プリンティング技術こそが、そのような信仰の対象だったのです。","ENG":"To us, this Mental Printing technology was the object of such faith.","TWN":"對我們來講，智力複印技術就是在複製信念。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"처음부터 끝까지 당신은….","JPN":"最初から最後まで君は……","ENG":"From start until finish, you were...","TWN":"你自始自終都是一個……"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"아니, 우리는 정말이지 구역질 나는 인간이었어.","JPN":"いや、私たちは本当に反吐が出る人間だった。","ENG":"No, we were really disgusting human beings.","TWN":"不，我們都是一個令人噁心的人類。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"어디로 가시려 하는지요?","JPN":"どこに行かれるのですか？","ENG":"Where might you be heading off to?","TWN":"你要去哪裡？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"여기에 더 이상 볼일은 없으니까.","JPN":"もうここに用はない。","ENG":"There's nothing more for me here.","TWN":"我沒有必要繼續留在這裡。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L47_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"이제 남은 곳은…. 한 군데뿐이야.","JPN":"残ってるのは……あと一か所だけ。","ENG":"There's... only one place remaining.","TWN":"現在……只剩下最後一個地方。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};